55	const PROCESSING_FEE = 5;
56	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
57	const CURSE_SURCHARGE_RATE = 0.5;
58	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
59	const HIGH_ENCHANTMENT_MINIMUM = 5;
60	const LOYALTY_DISCOUNT_RATE = 0.2;
61	const LOYALTY_MINIMUM_YEARS = 2;
62	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
63	
64	const BASE_PREMIUMS: Record<string, number> = {
65	  sword: 100,
66	  amulet: 60,
67	  staff: 80,
68	  potion: 40,
69	  rune: 25,
70	  moonstone: 25,
71	};
72	
73	const COMPONENT_BLOCK_SIZE = 3;
74	const COMPONENT_BLOCK_PREMIUM = 60;
75	
76	const countByType = (items: Item[]): Map<string, number> => {
77	  const counts = new Map<string, number>();
78	  for (const item of items) {
79	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
80	  }
81	  return counts;
82	};
83	
84	const groupBasePremium = (type: string, count: number): number =>
85	  count === COMPONENT_BLOCK_SIZE
86	    ? COMPONENT_BLOCK_PREMIUM
87	    : count * BASE_PREMIUMS[type];
88	
89	const computeBasePremium = (items: Item[]): number =>
90	  [...countByType(items)].reduce(
91	    (total, [type, count]) => total + groupBasePremium(type, count),
92	    0,
93	  );
94	
95	const sumBy = (items: Item[], amount: (item: Item) => number): number =>
96	  items.reduce((total, item) => total + amount(item), 0);
97	
98	const itemCurseSurcharge = (item: Item): number =>
99	  item.cursed ? BASE_PREMIUMS[item.type] * CURSE_SURCHARGE_RATE : 0;
100	
101	const itemHighEnchantmentSurcharge = (item: Item): number =>
102	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_MINIMUM
103	    ? BASE_PREMIUMS[item.type] * HIGH_ENCHANTMENT_SURCHARGE_RATE
104	    : 0;
105	
106	const quotePremium = (
107	  customer: Customer,
108	  items: Item[],
109	  isFollowUp: boolean,
110	): number => {
111	  const basePremium = computeBasePremium(items);
112	  const curseSurcharge = sumBy(items, itemCurseSurcharge);
113	  const highEnchantmentSurcharge = sumBy(items, itemHighEnchantmentSurcharge);
114	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
115	  const loyaltyDiscount =
116	    customer.yearsWithMHPCO >= LOYALTY_MINIMUM_YEARS
117	      ? basePremium * LOYALTY_DISCOUNT_RATE
118	      : 0;
119	  const followUpDiscount = isFollowUp
120	    ? basePremium * FOLLOW_UP_DISCOUNT_RATE
121	    : 0;
122	  const exactPremium =
123	    basePremium +
124	    curseSurcharge +
125	    highEnchantmentSurcharge +
126	    firstInsuranceSurcharge -
127	    loyaltyDiscount -
128	    followUpDiscount +
129	    PROCESSING_FEE;
130	  return Math.ceil(exactPremium);
131	};
132	
133	const processClaim = (): ClaimResult => ({
134	  payout: 400,
135	  remainingCap: 1600,
136	});
137	
138	export const processScenario = (scenario: Scenario): { results: Result[] } => ({
139	  results: scenario.steps.map((step, index) =>
140	    step.op === "quote"
141	      ? { premium: quotePremium(scenario.customer, step.items, index > 0) }
142	      : processClaim(),
143	  ),
144	});
